          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col">
        {view === 'privacy' ? (
          <PrivacyPolicy onBack={() => setView('editor')} />
        ) : (
          <main className="max-w-7xl mx-auto p-4 lg:p-8 w-full flex flex-col lg:flex-row gap-8 overflow-hidden">
            {/* Left Column: Controls */}
            <div className="w-full lg:w-1/3 lg:h-[calc(100vh-12rem)] lg:overflow-hidden flex flex-col order-2 lg:order-1">
