    ctx.arcTo(x + w, y + h, x, y + h, r);
    ctx.arcTo(x, y + h, x, y, r);
    ctx.arcTo(x, y, x + w, y, r);
    ctx.closePath();
  };

  const renderPin = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number, scaleFactor: number = 1.0) => {
    ctx.clearRect(0, 0, width, height);
    if (bgImageObj && !variation?.fallbackMode) {
      const scale = Math.max(width / bgImageObj.width, height / bgImageObj.height) * scaleFactor;
      const w = bgImageObj.width * scale;
      const h = bgImageObj.height * scale;
      ctx.drawImage(bgImageObj, (width - w) / 2, (height - h) / 2, w, h);
    } else {
      const grad = ctx.createLinearGradient(0, 0, width, height);
      grad.addColorStop(0, '#f87171'); grad.addColorStop(1, '#c026d3');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, width, height);
    }

    let alpha = 0.2;
    let textCol = config.textColor;
    let outCol = config.outlineColor;

    if (config.colorScheme === 'dark-overlay') { alpha = 0.6; textCol = '#ffffff'; }
    else if (config.colorScheme === 'monochrome') {
       ctx.save(); ctx.globalCompositeOperation = 'saturation'; ctx.fillStyle = 'black'; ctx.fillRect(0,0,width,height); ctx.restore();
       textCol = '#ffffff'; outCol = '#000000';
    }
    ctx.fillStyle = `rgba(0,0,0,${alpha})`;
    ctx.fillRect(0, 0, width, height);

    if (config.headline) {
      const size = calculateOptimalFontSize(ctx, config.headline, width * 0.9, height * 0.55, config.fontFamily);
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.font = `bold ${size}px ${config.fontFamily}`;
      const lines = getLines(ctx, config.headline, width * 0.9);
      const lh = size * 1.2;
      let cy = (height * (config.textYPos / 100)) - ((lines.length * lh) / 2) + (lh / 2);
      lines.forEach(l => {
        ctx.strokeStyle = outCol; ctx.lineWidth = size * 0.25; ctx.lineJoin = 'round'; ctx.strokeText(l, width/2, cy);
        ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 20; ctx.shadowOffsetY = 10;
        ctx.fillStyle = textCol; ctx.fillText(l, width/2, cy);
        ctx.shadowColor = 'transparent'; cy += lh;
      });
    }

    if (config.showCta && config.ctaText) {
      const py = height * 0.92; const bw = width * 0.9; const bh = 120;
      let fs = 45; ctx.font = `bold ${fs}px ${config.fontFamily}`;
      const tw = ctx.measureText(config.ctaText).width;
      if (tw > bw * 0.8) fs *= (bw * 0.8 / tw);
      ctx.font = `bold ${fs}px ${config.fontFamily}`;
      ctx.shadowColor = 'rgba(0,0,0,0.4)'; ctx.shadowBlur = 15; ctx.shadowOffsetY = 8;
      ctx.fillStyle = config.ctaBgColor;
      drawRoundedRect(ctx, (width - bw) / 2, py - (bh/2), bw, bh, bh/2);
      ctx.fill();
      ctx.shadowColor = 'transparent'; ctx.fillStyle = config.ctaTextColor; ctx.textAlign = 'center';
      ctx.fillText(config.ctaText, width/2, py + 4);
    }

    if (config.brandText) {
      ctx.font = `bold 24px ${config.fontFamily}`; ctx.fillStyle = config.brandColor;
      ctx.fillText(config.brandText, width/2, config.showCta ? height * 0.85 : height - 40);
    }
  }, [variation, config, bgImageObj]);

  useEffect(() => {
    if (isRecording) return;
    const c = canvasRef.current;
    if (!c) return;
    const ctx = c.getContext('2d');
    if (!ctx) return;
    c.width = 1000; c.height = 1500;
    renderPin(ctx, 1000, 1500, 1.0);
  }, [renderPin, isRecording]);

  const handleDownload = () => {
    const c = canvasRef.current; if (!c) return;

    // Automatically copy title to clipboard
    if (variation?.seoTitle) {
      navigator.clipboard.writeText(variation.seoTitle).catch(err => {
        console.error('Failed to copy title to clipboard:', err);
      });
    }

    const link = document.createElement('a');
    link.download = `pin-${Date.now()}.png`; link.href = c.toDataURL('image/png'); link.click();
  };

  const handleRecord = () => {
    const c = canvasRef.current; if (!c || !bgImageObj) return;
    setIsRecording(true);

    // Detect best supported format for MP4 request
    const types = [
      'video/mp4',
      'video/mp4;codecs=h264',
      'video/webm;codecs=h264',
      'video/webm'
    ];
    const supportedType = types.find(t => MediaRecorder.isTypeSupported(t)) || 'video/webm';

    const stream = c.captureStream(30);
    const chunks: BlobPart[] = [];
    const recorder = new MediaRecorder(stream, { mimeType: supportedType });

    recorder.ondataavailable = (e) => chunks.push(e.data);
    recorder.onstop = () => {
      const b = new Blob(chunks, { type: supportedType });
      const l = document.createElement('a');
      l.download = `pin-video-${Date.now()}.mp4`; // Always download as .mp4
      l.href = URL.createObjectURL(b); 
      l.click();
      setIsRecording(false);
    };

    recorder.start();
    const ctx = c.getContext('2d');
    const start = performance.now();
    const animate = (t: number) => {
      const prog = Math.min((t - start) / 5000, 1);
      setRecordingProgress(Math.round(prog * 100));
      if (ctx) renderPin(ctx, 1000, 1500, 1.1 - (0.1 * prog));
      if (prog < 1) requestAnimationFrame(animate); else recorder.stop();
    };
    requestAnimationFrame(animate);
  };

  return (
    <div className="flex flex-col items-center">
      {variation && (
        <div className="w-full max-w-[500px] flex justify-between items-center mb-4 gap-2">
           <button onClick={handleRecord} disabled={isRecording || !bgImageObj} className={`px-4 py-2 rounded-lg text-xs font-bold uppercase transition-all flex items-center gap-2 border ${isRecording ? 'bg-red-50 text-red-600 border-red-200' : 'bg-white text-slate-700 border-slate-200 hover:border-red-600'}`}>
            {isRecording ? <Loader2 className="w-4 h-4 animate-spin" /> : <Video className="w-4 h-4" />}
            {isRecording ? `${recordingProgress}%` : 'Video'}
          </button>
          <button onClick={handleDownload} disabled={isRecording} className="bg-slate-900 text-white px-4 py-2 rounded-lg text-xs font-bold uppercase hover:bg-slate-800 flex items-center gap-2">
            <Download className="w-4 h-4" /> Download
          </button>
        </div>
      )}
      <div className="relative shadow-2xl rounded-2xl overflow-hidden bg-white ring-1 ring-slate-900/5 aspect-[2/3] w-full max-w-[500px]">
        {(isGeneratingText || isLoadingImage) && (
          <div className="absolute inset-0 z-10 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center text-slate-500">
            <Loader2 className="w-10 h-10 animate-spin text-red-600 mb-4" />
            <p className="font-bold text-xs uppercase tracking-widest">{isGeneratingText ? 'Planning Content...' : 'Developing Aesthetic...'}</p>
          </div>
        )}
        {!variation && !isGeneratingText && (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 bg-slate-50">
            <ImageIcon className="w-12 h-12 mb-4 opacity-20" />
            <p className="text-sm font-bold uppercase tracking-widest">Pin Studio</p>
          </div>
        )}
        <canvas ref={canvasRef} className="w-full h-full object-contain block" />
      </div>
    </div>
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { Sparkles, Shield } from 'lucide-react';
import { ControlPanel } from './components/ControlPanel';
import { CanvasPreview, CanvasPreviewHandle } from './components/CanvasPreview';
import { PrivacyPolicy } from './components/PrivacyPolicy';
import { generatePinVariations, generatePinImage } from './services/geminiService';
import { PinVariation, PinConfig, FONTS } from './types';

type View = 'editor' | 'privacy';

export default function App() {
  const canvasPreviewRef = useRef<CanvasPreviewHandle>(null);

  // Navigation State
  const [view, setView] = useState<View>('editor');

  // Data State
  const [keyword, setKeyword] = useState('');
  const [baseUrl, setBaseUrl] = useState('');
  const [variations, setVariations] = useState<PinVariation[]>([]);
  const [currentVarIndex, setCurrentVarIndex] = useState(0);

  // UI State
  const [isGeneratingText, setIsGeneratingText] = useState(false);
  const [loadingImages, setLoadingImages] = useState<Record<number, boolean>>({});
  const [errorMsg, setErrorMsg] = useState('');

  // Configuration State
  const [config, setConfig] = useState<PinConfig>({
    headline: 'Your Catchy Headline Here',
    ctaText: 'Check it out',
    showCta: true,
    brandText: '',
    fontFamily: FONTS[0].value,
    textColor: '#000000',
    outlineColor: '#ffffff',
    brandColor: '#ffffff',
    ctaBgColor: '#e60023',
    ctaTextColor: '#ffffff',
    textYPos: 45,
    colorScheme: 'standard'
  });

  const handleGenerate = async () => {
    if (!keyword.trim()) return;
    setIsGeneratingText(true);
    setErrorMsg('');
    setVariations([]);
    setLoadingImages({});

    try {
      const data = await generatePinVariations(keyword);
      if (data.variations && data.variations.length > 0) {
        const newVariations: PinVariation[] = data.variations.map(v => ({
          ...v,
          imageUrl: null,
          fallbackMode: false
        }));
        setVariations(newVariations);
        setCurrentVarIndex(0);
        const firstVar = newVariations[0];
        setConfig(prev => ({
          ...prev,
          headline: firstVar.headline,
          ctaText: firstVar.ctaText,
          showCta: true
        }));
      } else {
        throw new Error("No variations generated.");
      }
    } catch (error: any) {
      setErrorMsg(error.message || "Failed to generate content.");
    } finally {
      setIsGeneratingText(false);
    }
  };

  const handleUpdateSEO = (newSeo: { title: string, description: string, hashtags: string }) => {
    setVariations(prev => {
      const updated = [...prev];
      if (updated[currentVarIndex]) {
        updated[currentVarIndex] = {
          ...updated[currentVarIndex],
          seoTitle: newSeo.title,
          seoDescription: newSeo.description,
          hashtags: newSeo.hashtags
        };
      }
      return updated;
    });
  };

  const handleSelectVariation = (index: number) => {
    setCurrentVarIndex(index);
    const selectedVar = variations[index];
    if (selectedVar) {
      setConfig(prev => ({
        ...prev,
        headline: selectedVar.headline,
        ctaText: selectedVar.ctaText
      }));
    }
  };

  useEffect(() => {
    const generateImageIfNeeded = async () => {
      const currentVar = variations[currentVarIndex];
      if (currentVar && !currentVar.imageUrl && !currentVar.fallbackMode && !loadingImages[currentVarIndex] && !isGeneratingText) {
        setLoadingImages(prev => ({ ...prev, [currentVarIndex]: true }));
        try {
          const base64Image = await generatePinImage(currentVar.imagePrompt);
          setVariations(prev => {
            const newVars = [...prev];
            newVars[currentVarIndex] = { ...newVars[currentVarIndex], imageUrl: base64Image };
            return newVars;
          });
        } catch (e) {
          setVariations(prev => {
            const newVars = [...prev];
            newVars[currentVarIndex] = { ...newVars[currentVarIndex], fallbackMode: true };
            return newVars;
          });
        } finally {
          setLoadingImages(prev => ({ ...prev, [currentVarIndex]: false }));
        }
      }
    };
    generateImageIfNeeded();
  }, [currentVarIndex, variations, loadingImages, isGeneratingText]);

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans selection:bg-red-100 selection:text-red-600 flex flex-col">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shrink-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <button onClick={() => setView('editor')} className="flex items-center gap-2 hover:opacity-80 transition-opacity">
            <div className="bg-red-600 p-2 rounded-full shadow-sm">
              <Sparkles className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">PinGenius AI</h1>
          </button>
          <div className="hidden md:flex items-center gap-4">
             <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-100 px-2 py-1 rounded">PRO</span>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col">
        {view === 'privacy' ? (
          <PrivacyPolicy onBack={() => setView('editor')} />
        ) : (
          <main className="flex-1 max-w-7xl mx-auto p-4 lg:p-8 w-full flex flex-col lg:flex-row gap-8 overflow-hidden">
            <div className="w-full lg:w-1/3 lg:h-[calc(100vh-12rem)] lg:overflow-hidden flex flex-col order-2 lg:order-1">
              <ControlPanel 
                keyword={keyword}
                setKeyword={setKeyword}
                baseUrl={baseUrl}
                setBaseUrl={setBaseUrl}
                onGenerate={handleGenerate}
                onUpdateSEO={handleUpdateSEO}
                isGenerating={isGeneratingText}
                variations={variations}
                currentVarIndex={currentVarIndex}
                onSelectVariation={handleSelectVariation}
                config={config}
                setConfig={setConfig}
                loadingImages={loadingImages}
                errorMsg={errorMsg}
              />
            </div>
            <div className="w-full lg:w-2/3 order-1 lg:order-2 flex flex-col items-center justify-start lg:pt-4">
              <CanvasPreview 
                ref={canvasPreviewRef}
                variation={variations[currentVarIndex] || null}
                config={config}
                imageUrl={variations[currentVarIndex]?.imageUrl}
                isLoadingImage={loadingImages[currentVarIndex]}
                isGeneratingText={isGeneratingText}
              />
            </div>
          </main>
        )}
      </div>

      <footer className="bg-white border-t border-slate-200 py-10 shrink-0">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex flex-col items-center md:items-start gap-2">
            <div className="flex items-center gap-2 text-slate-900 font-bold">
              <Sparkles className="w-4 h-4 text-red-600" />
              <span>PinGenius AI</span>
            </div>
            <p className="text-xs text-slate-400">© {new Date().getFullYear()} AI-powered design for Pinterest creators.</p>
          </div>
          <div className="flex flex-wrap justify-center items-center gap-x-8 gap-y-4">
            <button onClick={() => setView('privacy')} className="text-xs font-semibold text-slate-500 hover:text-red-600 transition-colors flex items-center gap-2">
              <Shield className="w-3.5 h-3.5" />
              Privacy Policy
            </button>
            <a href="https://ai.google.dev" target="_blank" rel="noopener noreferrer" className="text-xs font-semibold text-slate-500 hover:text-slate-900 transition-colors">Google Gemini</a>
            <span className="hidden md:inline text-slate-200">|</span>
            <p className="text-[10px] font-bold text-slate-300 uppercase tracking-tighter">Pinterest Authorized</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState } from 'react';
import { 
  Palette, 
  Layout, 
  Droplet, 
  Layers, 
  Check, 
  Copy, 
  MousePointerClick,
  Loader2,
  Sparkles,
  Zap,
  Wand2,
  Eye,
  EyeOff,
  Type as FontIcon,
  Tag,
  Link as LinkIcon,
  ExternalLink
} from 'lucide-react';
import { PinConfig, PinVariation, FONTS } from '../types';
import { rephraseCTA, generateSEOMetadata } from '../services/geminiService';

interface ControlPanelProps {
  keyword: string;
  setKeyword: (k: string) => void;
  baseUrl: string;
  setBaseUrl: (url: string) => void;
  onGenerate: () => void;
  onUpdateSEO: (seo: { title: string, description: string, hashtags: string }) => void;
  isGenerating: boolean;
  variations: PinVariation[];
  currentVarIndex: number;
  onSelectVariation: (idx: number) => void;
  config: PinConfig;
  setConfig: (c: PinConfig) => void;
  loadingImages: Record<number, boolean>;
  errorMsg: string;
}

const COLOR_SCHEMES = [
  { id: 'standard', name: 'Standard', icon: Palette },
  { id: 'monochrome', name: 'Monochrome', icon: Droplet },
  { id: 'dark-overlay', name: 'Dark Overlay', icon: Layers },
];

const slugify = (text: string) => {
  return text
    .toLowerCase()
    .trim()
    .replace(/[^\w\s-]/g, '')
    .replace(/[\s_-]+/g, '-')
    .replace(/^-+|-+$/g, '');
};

export const ControlPanel: React.FC<ControlPanelProps> = ({
  keyword,
  setKeyword,
  baseUrl,
  setBaseUrl,
  onGenerate,
  onUpdateSEO,
  isGenerating,
  variations,
  currentVarIndex,
  onSelectVariation,
  config,
  setConfig,
  loadingImages,
  errorMsg
}) => {
  const [copiedTitle, setCopiedTitle] = useState(false);
  const [copiedDesc, setCopiedDesc] = useState(false);
  const [copiedUrl, setCopiedUrl] = useState(false);
  const [isRephrasing, setIsRephrasing] = useState(false);
  const [isEnhancingSEO, setIsEnhancingSEO] = useState(false);
  const [ctaSuggestions, setCtaSuggestions] = useState<string[]>([]);

  const currentVariation = variations[currentVarIndex];
  const smartUrl = currentVariation && baseUrl 
    ? `${baseUrl}${baseUrl.includes('?') ? '&' : '?'}${slugify(currentVariation.seoTitle)}`
    : baseUrl;

  const copyToClipboard = (text: string, setter: (v: boolean) => void) => {
    navigator.clipboard.writeText(text).then(() => {
      setter(true);
      setTimeout(() => setter(false), 2000);
    });
  };

  const updateConfig = (key: keyof PinConfig, value: any) => {
    setConfig({ ...config, [key]: value });
  };

  const handleMagicRephrase = async () => {
    if (!config.headline || isRephrasing) return;
    setIsRephrasing(true);
    try {
      const suggestions = await rephraseCTA(config.headline);
      setCtaSuggestions(suggestions);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRephrasing(false);
    }
  };

  const handleMagicSEO = async () => {
    if (!config.headline || isEnhancingSEO) return;
    setIsEnhancingSEO(true);
    try {
      const seo = await generateSEOMetadata(config.headline, keyword);
      onUpdateSEO(seo);
    } catch (e) {
      console.error(e);
    } finally {
      setIsEnhancingSEO(false);
    }
  };

  return (
    <div className="flex flex-col gap-6 h-full pb-10">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 shrink-0">
        <label className="block text-sm font-semibold text-slate-700 mb-2">Pin Topic</label>
        <div className="flex gap-2">
          <input 
            type="text" 
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
            placeholder="e.g. Woodworking Plans"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-red-500/20 focus:border-red-500"
            onKeyDown={(e) => e.key === 'Enter' && onGenerate()}
          />
          <button 
            onClick={onGenerate}
            disabled={isGenerating || !keyword.trim()}
            className={`px-6 py-3 rounded-xl font-semibold text-white transition-all flex items-center gap-2 ${
              isGenerating || !keyword.trim() ? 'bg-slate-300 cursor-not-allowed' : 'bg-red-600 hover:bg-red-700 shadow-md'
            }`}
          >
            {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
            Create
          </button>
        </div>
        {errorMsg && (
          <div className="mt-3 text-xs p-2 rounded-lg border text-amber-600 bg-amber-50 border-amber-100">
            {errorMsg}
          </div>
        )}
      </div>

      {variations.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex-1 flex flex-col min-h-0">
          <div className="p-4 bg-slate-50 border-b border-slate-100 shrink-0 flex justify-between items-center">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
              <Layers className="w-3 h-3" /> Variation
            </label>
            <div className="flex gap-1">
              {variations.map((_, idx) => (
                <button
                  key={idx}
                  onClick={() => onSelectVariation(idx)}
                  className={`w-8 h-8 rounded-lg text-xs font-bold transition-all border ${currentVarIndex === idx ? 'bg-red-600 border-red-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-red-300'}`}
                >
                  {loadingImages[idx] ? <Loader2 className="w-3 h-3 animate-spin mx-auto" /> : idx + 1}
                </button>
              ))}
            </div>
          </div>

          <div className="p-6 space-y-8 overflow-y-auto custom-scrollbar flex-1">

            {/* Destination URL Section */}
            <div className="space-y-6">
              <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                <LinkIcon className="w-4 h-4 text-red-600" />
                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Destination URL</h3>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase">Base Link</label>
                  <input 
                    type="url" 
                    value={baseUrl}
                    onChange={(e) => setBaseUrl(e.target.value)}
                    placeholder="https://mysite.com/product"
                    className="w-full px-3 py-2 rounded-lg border border-slate-200 text-sm focus:border-red-500 outline-none"
                  />
                </div>

                {baseUrl && (
                  <div className="p-3 bg-slate-50 rounded-xl border border-dashed border-slate-200 space-y-2 animate-in fade-in duration-300">
                    <div className="flex justify-between items-center">
                      <label className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
                        <ExternalLink className="w-2.5 h-2.5" /> Generated Smart URL
                      </label>
                      <button 
                        onClick={() => copyToClipboard(smartUrl, setCopiedUrl)}
                        className="text-slate-400 hover:text-red-600 transition-colors flex items-center gap-1"
                      >
                        {copiedUrl ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
                        <span className="text-[10px] font-bold uppercase">{copiedUrl ? 'Copied' : 'Copy'}</span>
                      </button>
                    </div>
                    <p className="text-[11px] text-slate-500 break-all font-mono line-clamp-2 bg-white p-2 rounded border border-slate-100">
                      {smartUrl}
                    </p>
                  </div>
                )}
              </div>
            </div>

            <div className="h-px bg-slate-100" />

            {/* Pinterest Metadata Section */}
            <div className="space-y-6">
              <div className="flex items-center justify-between pb-2 border-b border-slate-100">
                <div className="flex items-center gap-2">
                  <Tag className="w-4 h-4 text-red-600" />
                  <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Pinterest SEO</h3>
                </div>
                <button 
                  onClick={handleMagicSEO}
                  disabled={isEnhancingSEO}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all shadow-sm border ${isEnhancingSEO ? 'bg-slate-50 text-slate-400 border-slate-100 cursor-not-allowed' : 'bg-white text-red-600 border-red-100 hover:bg-red-50 hover:scale-105 active:scale-95'}`}
                >
                  {isEnhancingSEO ? <Loader2 className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                  {isEnhancingSEO ? 'Optimizing...' : 'Magic Enhance'}
                </button>
              </div>

              {currentVariation && (
                <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div className="space-y-2">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-2">
                        <label className="text-[10px] font-bold text-slate-400 uppercase">Pin Title</label>
                        <button 
                          onClick={() => copyToClipboard(currentVariation.seoTitle, setCopiedTitle)} 
                          className="text-slate-400 hover:text-red-600 transition-colors"
                          title="Copy Title"
                        >
                          {copiedTitle ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
                        </button>
                      </div>
                      <span className="text-[9px] bg-emerald-50 text-emerald-600 px-1.5 py-0.5 rounded-full font-bold">SEO OPTIMIZED</span>
                    </div>
                    <input 
                      type="text" 
                      value={currentVariation.seoTitle}
                      onChange={(e) => onUpdateSEO({ ...currentVariation, title: e.target.value })}
                      className="w-full px-3 py-2 rounded-lg border border-slate-200 text-sm focus:border-red-500 outline-none"
                    />
                  </div>

                  <div className="space-y-2">
                    <div className="flex justify-between items-center">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Description (Inc. Hashtags)</label>
                      <button onClick={() => copyToClipboard(currentVariation.seoDescription, setCopiedDesc)} className="text-slate-400 hover:text-red-600 transition-colors" title="Copy Description & Tags">
                        {copiedDesc ? <Check className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
                      </button>
                    </div>
                    <textarea 
                      value={currentVariation.seoDescription}
                      onChange={(e) => onUpdateSEO({ ...currentVariation, description: e.target.value, title: currentVariation.seoTitle })}
                      className="w-full p-3 rounded-lg border border-slate-200 text-sm focus:border-red-500 outline-none h-48 resize-none leading-relaxed font-normal"
                      placeholder="Enter description and hashtags..."
                    />
                  </div>
                </div>
              )}
            </div>

            <div className="h-px bg-slate-100" />

            {/* CTA Section */}
            <div className="space-y-6">
              <div className="flex items-center justify-between pb-2 border-b border-slate-100">
                <div className="flex items-center gap-2">
                  <MousePointerClick className="w-4 h-4 text-red-600" />
                  <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">CTA Button</h3>
                </div>
                <button 
                  onClick={() => updateConfig('showCta', !config.showCta)}
                  className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[10px] font-bold uppercase transition-all ${config.showCta ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}
                >
                  {config.showCta ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
                  {config.showCta ? 'Visible' : 'Hidden'}
                </button>
              </div>

              {config.showCta && (
                <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div className="flex gap-2">
                    <input 
                      type="text" 
                      value={config.ctaText}
                      onChange={(e) => updateConfig('ctaText', e.target.value)}
                      className="flex-1 px-3 py-2 rounded-lg border border-slate-200 text-sm focus:border-red-500 outline-none"
                      placeholder="e.g. Shop Now"
                      maxLength={25}
                    />
                    <button 
                      onClick={handleMagicRephrase}
                      disabled={isRephrasing}
                      title="Magic Rephrase with AI"
                      className="p-2 rounded-lg bg-slate-900 text-white hover:bg-slate-800 transition-colors disabled:opacity-50"
                    >
                      {isRephrasing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                    </button>
                  </div>

                  {(ctaSuggestions.length > 0 || isRephrasing) && (
                    <div className="flex flex-wrap gap-1.5 p-3 bg-slate-50 rounded-xl border border-slate-100">
                      <p className="w-full text-[10px] font-bold text-slate-400 uppercase mb-1 flex items-center gap-1">
                        <Zap className="w-2.5 h-2.5 text-amber-500 fill-current" /> AI Suggestions
                      </p>
                      {isRephrasing ? (
                        <div className="h-6 w-full animate-pulse bg-slate-200 rounded"></div>
                      ) : (
                        ctaSuggestions.map(s => (
                          <button
                            key={s}
                            onClick={() => updateConfig('ctaText', s)}
                            className="px-2 py-1 rounded-md bg-white border border-slate-200 text-[10px] font-bold text-slate-600 hover:border-red-300 hover:text-red-600 transition-all"
                          >
                            {s}
                          </button>
                        ))
                      )}
                    </div>
                  )}

                  <div className="grid grid-cols-2 gap-4">
                    <div className="flex items-center gap-2">
                       <label className="text-[10px] text-slate-400 font-bold uppercase">Bg</label>
                       <input type="color" value={config.ctaBgColor} onChange={(e) => updateConfig('ctaBgColor', e.target.value)} className="w-8 h-8 rounded-lg cursor-pointer border border-slate-200" />
                    </div>
                    <div className="flex items-center gap-2">
                       <label className="text-[10px] text-slate-400 font-bold uppercase">Text</label>
                       <input type="color" value={config.ctaTextColor} onChange={(e) => updateConfig('ctaTextColor', e.target.value)} className="w-8 h-8 rounded-lg cursor-pointer border border-slate-200" />
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="space-y-6">
              <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                <FontIcon className="w-4 h-4 text-red-600" />
                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Canvas Content</h3>
              </div>
              <textarea 
                value={config.headline}
                onChange={(e) => updateConfig('headline', e.target.value)}
                className="w-full p-3 rounded-lg border border-slate-200 text-sm focus:border-red-500 outline-none resize-none h-20"
              />
              <div>
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">Vertical Position</label>
                  <input type="range" min="10" max="90" value={config.textYPos} onChange={(e) => updateConfig('textYPos', Number(e.target.value))} className="w-full accent-red-600 h-2 bg-slate-100 rounded-lg appearance-none" />
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                <Palette className="w-4 h-4 text-red-600" />
                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Visual Style</h3>
              </div>
              <div className="grid grid-cols-3 gap-2">
                {COLOR_SCHEMES.map(s => {
                  const Icon = s.icon;
                  return (
                    <button key={s.id} onClick={() => updateConfig('colorScheme', s.id)} className={`flex flex-col items-center p-2 rounded-lg border text-[10px] font-bold uppercase transition-all ${config.colorScheme === s.id ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 hover:border-slate-300'}`}>
                      <Icon className="w-4 h-4 mb-1" />{s.name}
                    </button>
                  );
                })}
              </div>
              <select value={config.fontFamily} onChange={(e) => updateConfig('fontFamily', e.target.value)} className="w-full p-2 rounded-lg border border-slate-200 text-sm bg-white outline-none">
                {FONTS.map(f => <option key={f.name} value={f.value}>{f.name}</option>)}
              </select>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
